  const tagOptions = { cacheDir, noAi, model }
  const tags: Record<string, string[]> = {}
  await Promise.all(
    manifests.map(async m => {
      const summary = summaries[m.session_id] ?? ''
      tags[m.session_id] = await getTags(m.raw_sha256, summary, tagOptions)
    }),
  )

